func TestGettersX509CertificateCredential(t *testing.T) {
	t.Run("GetCredentialType", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &X509CertificateCredential{}
		var expected X509CertificateCredentialTypeEnum
		obj.CredentialType = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetCredentialType(), "getter should return the property value")
	})

	t.Run("GetCredentialType_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *X509CertificateCredential
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetCredentialType() // Should return zero value
	})

	t.Run("GetName", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &X509CertificateCredential{}
		var value string
		obj.Name = &value

		// Act & Assert
		assert.Equal(t, value, obj.GetName(), "getter should dereference and return the value")
	})

	t.Run("GetName_NilProperty", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &X509CertificateCredential{}
		obj.Name = nil
		var expectedZero string

		// Act & Assert
		assert.Equal(t, expectedZero, obj.GetName(), "getter should return zero value when property is nil")
	})

	t.Run("GetName_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *X509CertificateCredential
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetName() // Should return zero value
	})

	t.Run("GetPem", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &X509CertificateCredential{}
		var expected string
		obj.Pem = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetPem(), "getter should return the property value")
	})

	t.Run("GetPem_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *X509CertificateCredential
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetPem() // Should return zero value
	})

}

